
'use client';

import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Separator } from '@/components/ui/separator';
import { Button } from '@/components/ui/button';
import { type QuoteItem } from '@/components/quote-form-live';
import { Service } from '@/lib/types';
import { MinusCircle, PlusCircle } from 'lucide-react';
import { allItems } from '@/lib/items';


interface LiveQuoteSummaryProps {
  quoteItems: QuoteItem[];
  rentalDurationWeeks: number;
  onItemChange: (itemId: string, quantity: number, type: 'hire' | 'purchase') => void;
}

export function LiveQuoteSummary({
  quoteItems,
  rentalDurationWeeks,
  onItemChange,
}: LiveQuoteSummaryProps) {

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-AU', {
      style: 'currency',
      currency: 'AUD',
    }).format(amount);
  };
  
  const calculateItemTotal = (item: QuoteItem) => {
    const serviceItem = allItems.find((s) => s.id === item.id);
    if (!serviceItem) return 0;

    let price = 0;
    if (item.type === 'hire' && serviceItem.options.hire) {
      price = serviceItem.options.hire.price * rentalDurationWeeks;
    } else if (item.type === 'purchase' && serviceItem.options.purchase) {
      price = serviceItem.options.purchase.price;
    } else if (serviceItem.options.unit) { // For items like 'Extra Week Hire'
        price = serviceItem.options.unit.price;
    } else if (serviceItem.options.hire) { // Fallback for items with only hire option
        price = serviceItem.options.hire.price * rentalDurationWeeks;
    }

    return item.quantity * price;
  };

  const total = quoteItems.reduce(
    (acc, item) => acc + calculateItemTotal(item),
    0
  );

  return (
    <Card className="sticky top-24">
      <CardHeader>
        <CardTitle>Your Live Quote</CardTitle>
        <CardDescription>
          Your estimated quote will update as you add or remove items.
        </CardDescription>
      </CardHeader>
      <CardContent className="max-h-96 overflow-y-auto">
        {quoteItems.length === 0 ? (
          <p className="text-muted-foreground">
            Your quote is currently empty. Add some items to get started!
          </p>
        ) : (
          <div className="space-y-4">
            {quoteItems.map((item) => {
                const serviceItem = allItems.find(s => s.id === item.id);
                if (!serviceItem) return null;
              return (
                <div key={`${item.id}-${item.type}`} className="flex justify-between items-center">
                  <div>
                    <p className="font-medium">{serviceItem.name} ({item.type})</p>
                    <p className="text-sm text-muted-foreground">
                      {item.quantity} x {formatCurrency(calculateItemTotal(item) / item.quantity)}
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => onItemChange(item.id, item.quantity - 1, item.type)}>
                        <MinusCircle className="h-4 w-4" />
                    </Button>
                     <span className="font-bold text-lg">{formatCurrency(calculateItemTotal(item))}</span>
                     <Button variant="ghost" size="icon" className="h-6 w-6" onClick={() => onItemChange(item.id, item.quantity + 1, item.type)}>
                        <PlusCircle className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </CardContent>
      <CardFooter className="flex-col items-stretch space-y-4">
        <Separator />
        <div className="flex justify-between font-bold text-lg">
          <span>Estimated Total</span>
          <span>{formatCurrency(total)}</span>
        </div>
        <Button disabled={quoteItems.length === 0}>
          Proceed to Checkout
        </Button>
      </CardFooter>
    </Card>
  );
}
