
'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import { useForm } from 'react-hook-form';
import { z } from 'zod';
import { Button } from '@/components/ui/button';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { format, differenceInCalendarWeeks, add, parseISO } from 'date-fns';
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
} from '@/components/ui/card';
import {
  boxHireServices,
  services,
  protectionAddOns,
  tvProtectionAddOns,
} from '@/lib/data';
import { useState, useMemo } from 'react';
import { useToast } from '@/hooks/use-toast';
import { recommendAdditionalEquipment } from '@/ai/flows/recommend-additional-equipment';
import { Service } from '@/lib/types';
import { Textarea } from '@/components/ui/textarea';
import { allItems } from '@/lib/items';
import { LiveQuoteSummary } from './live-quote-summary';

export type QuoteItem = {
  id: string;
  quantity: number;
  type: 'hire' | 'purchase';
};

const formSchema = z.object({
  name: z.string().min(2, { message: 'Name must be at least 2 characters.' }),
  email: z.string().email({ message: 'Please enter a valid email.' }),
  projectDescription: z.string().optional(),
  rentalStartDate: z.date({
    required_error: 'A start date is required.',
  }),
  rentalEndDate: z.date({
    required_error: 'An end date is required.',
  }),
});

function ItemSelectionCard({
  item,
  onItemChange,
  quoteItems,
  rentalDurationWeeks,
}: {
  item: Service;
  onItemChange: (itemId: string, quantity: number, type: 'hire' | 'purchase') => void;
  quoteItems: QuoteItem[];
  rentalDurationWeeks: number;
}) {
  const hireItem = quoteItems.find(q => q.id === item.id && q.type === 'hire');
  const purchaseItem = quoteItems.find(q => q.id === item.id && q.type === 'purchase');

  const formatCurrency = (amount: number) => new Intl.NumberFormat('en-AU', { style: 'currency', currency: 'AUD' }).format(amount);

  const getPriceString = (type: 'hire' | 'purchase') => {
    const option = item.options[type];
    if (!option) return '';
    const price = type === 'hire' ? option.price * rentalDurationWeeks : option.price;
    return formatCurrency(price);
  };

  return (
    <Card className="flex flex-col">
      <CardHeader>
        <CardTitle className="text-lg">{item.name}</CardTitle>
        <CardDescription>{item.description}</CardDescription>
      </CardHeader>
      <CardContent className="flex-grow space-y-4">
        {Object.keys(item.options).map(key => {
          const type = key as 'hire' | 'purchase';
          if (!item.options[type]) return null;
          const currentQuantity = type === 'hire' ? hireItem?.quantity ?? 0 : purchaseItem?.quantity ?? 0;

          return (
            <div key={type} className="flex items-center justify-between gap-4 p-2 rounded-md border">
                <div>
                    <p className="font-semibold capitalize">{type}</p>
                    <p className="text-sm text-muted-foreground">{getPriceString(type)}</p>
                </div>
                <div className="flex items-center gap-2">
                    <Button size="icon" variant="outline" className="h-8 w-8" onClick={() => onItemChange(item.id, Math.max(0, currentQuantity - 1), type)} >-</Button>
                    <Input readOnly value={currentQuantity} className="h-8 w-12 text-center" />
                    <Button size="icon" variant="outline" className="h-8 w-8" onClick={() => onItemChange(item.id, currentQuantity + 1, type)} >+</Button>
                </div>
            </div>
          );
        })}
      </CardContent>
    </Card>
  );
}

export function QuoteFormLive() {
  const [isLoading, setIsLoading] = useState(false);
  const { toast } = useToast();
  const [recommendation, setRecommendation] = useState<{
    recommendedEquipment: string;
    reasoning: string;
  } | null>(null);

  const [quoteItems, setQuoteItems] = useState<QuoteItem[]>([]);
  
  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      name: '',
      email: '',
      projectDescription: '',
      rentalStartDate: new Date(),
      rentalEndDate: add(new Date(), { weeks: 2 }),
    },
  });

  const rentalStartDate = form.watch('rentalStartDate');
  const rentalEndDate = form.watch('rentalEndDate');

  const rentalDurationWeeks = useMemo(() => {
    if (!rentalStartDate || !rentalEndDate) return 1;
    if (rentalEndDate < rentalStartDate) return 1;

    const diffInWeeks = differenceInCalendarWeeks(rentalEndDate, rentalStartDate, { weekStartsOn: 1 });
    return Math.max(1, diffInWeeks);
  }, [rentalStartDate, rentalEndDate]);

  const handleItemChange = (itemId: string, quantity: number, type: 'hire' | 'purchase') => {
    setQuoteItems(prevItems => {
      const existingItemIndex = prevItems.findIndex(i => i.id === itemId && i.type === type);

      if (quantity <= 0) {
        if (existingItemIndex > -1) {
          return prevItems.filter((_, index) => index !== existingItemIndex);
        }
        return prevItems;
      }

      if (existingItemIndex > -1) {
        const newItems = [...prevItems];
        newItems[existingItemIndex] = { ...newItems[existingItemIndex], quantity };
        return newItems;
      } else {
        return [...prevItems, { id: itemId, quantity, type }];
      }
    });
  };
  
  const renderItemGroup = (title: string, items: Service[], description?: string) => (
    <div key={title}>
      <h3 className="text-2xl font-headline font-bold text-foreground mb-1">{title}</h3>
      {description && <p className="text-muted-foreground mb-6">{description}</p>}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {items.map(item => (
          <ItemSelectionCard
            key={item.id}
            item={item}
            onItemChange={handleItemChange}
            quoteItems={quoteItems}
            rentalDurationWeeks={rentalDurationWeeks}
          />
        ))}
      </div>
    </div>
  );

  async function onSubmit(values: z.infer<typeof formSchema>) {
    setIsLoading(true);
    setRecommendation(null);
    try {
      const selectedItemNames = quoteItems
        .map(item => {
          const serviceItem = allItems.find(s => s.id === item.id);
          return serviceItem ? `${serviceItem.name} (Qty: ${item.quantity}, Type: ${item.type})` : '';
        })
        .filter(Boolean)
        .join(', ');

      if (selectedItemNames) {
        const aiRecommendation = await recommendAdditionalEquipment({
          equipmentList: selectedItemNames,
        });

        if (aiRecommendation.recommendedEquipment) {
          setRecommendation(aiRecommendation);
        }
      }

      toast({
        title: 'Quote Request Submitted!',
        description: 'We have received your request and will get back to you shortly.',
      });
      console.log({ ...values, items: quoteItems, rentalDurationWeeks });
      form.reset();
      setQuoteItems([]);
    } catch (error) {
      console.error('Failed to submit quote or get recommendation', error);
      toast({
        variant: 'destructive',
        title: 'Submission Failed',
        description: 'There was a problem submitting your quote request. Please try again.',
      });
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
        <div className="lg:col-span-2 space-y-8">
             <Card>
                <CardHeader>
                    <CardTitle className="text-3xl font-headline">Request a Quote</CardTitle>
                    <CardDescription>
                    Fill out the form below and select your items to get a live quote. The default hire period is 2 weeks.
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
                        {/* User Details and Dates */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <FormField control={form.control} name="name" render={({ field }) => ( <FormItem> <FormLabel>Full Name</FormLabel> <FormControl> <Input placeholder="John Doe" {...field} /> </FormControl> <FormMessage /> </FormItem> )}/>
                            <FormField control={form.control} name="email" render={({ field }) => ( <FormItem> <FormLabel>Email Address</FormLabel> <FormControl> <Input placeholder="you@example.com" {...field} /> </FormControl> <FormMessage /> </FormItem> )}/>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                          <FormField
                            control={form.control}
                            name="rentalStartDate"
                            render={({ field }) => (
                              <FormItem>
                                <FormLabel>Rental Start Date</FormLabel>
                                <FormControl>
                                  <Input
                                    type="date"
                                    value={field.value ? format(field.value, 'yyyy-MM-dd') : ''}
                                    onChange={(e) => {
                                      if (e.target.value) {
                                        const date = parseISO(e.target.value);
                                        field.onChange(date);
                                        const currentEndDate = form.getValues('rentalEndDate');
                                        if (!currentEndDate || currentEndDate < date) {
                                          form.setValue('rentalEndDate', add(date, { weeks: 2 }));
                                        }
                                      }
                                    }}
                                    className="w-full"
                                  />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                          <FormField
                            control={form.control}
                            name="rentalEndDate"
                            render={({ field }) => (
                              <FormItem>
                                <FormLabel>Rental End Date</FormLabel>
                                <FormControl>
                                  <Input
                                    type="date"
                                    value={field.value ? format(field.value, 'yyyy-MM-dd') : ''}
                                    onChange={(e) => {
                                       if (e.target.value) {
                                        field.onChange(parseISO(e.target.value));
                                       }
                                    }}
                                    min={rentalStartDate ? format(add(rentalStartDate, {days: 1}), 'yyyy-MM-dd') : ''}
                                    className="w-full"
                                  />
                                </FormControl>
                                <FormMessage />
                              </FormItem>
                            )}
                          />
                        </div>
                        
                        <p className="text-sm text-muted-foreground">Rental duration: {rentalDurationWeeks} week(s)</p>

                        <FormField control={form.control} name="projectDescription" render={({ field }) => ( <FormItem> <FormLabel>Additional Information</FormLabel> <FormControl> <Textarea placeholder="Please add any quantities and special requests here." className="resize-none" {...field} /> </FormControl> <FormMessage /> </FormItem> )}/>
                        
                        {recommendation && (
                        <Card className="bg-blue-50 border-blue-200 dark:bg-blue-900/30">
                            <CardHeader>
                            <CardTitle className="text-xl font-headline text-blue-800 dark:text-blue-300">AI Recommendation</CardTitle>
                            </CardHeader>
                            <CardContent className="space-y-2">
                            <p>Based on your project, we also recommend: <span className="font-semibold">{recommendation.recommendedEquipment}</span></p>
                            <p className="text-sm text-muted-foreground">{recommendation.reasoning}</p>
                            </CardContent>
                        </Card>
                        )}
                        <Button type="submit" disabled={isLoading || quoteItems.length === 0}>
                            {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                        Submit Quote Request
                        </Button>
                    </form>
                    </Form>
                </CardContent>
            </Card>

            <div className="space-y-12">
                {renderItemGroup('Box Hire', boxHireServices, 'Hire is included for 2 weeks. Additional weeks can be purchased at a flat rate of $30 per week.')}
                {renderItemGroup('Optional Add-Ons', services, 'A range of additional items to help with your move.')}
                {renderItemGroup('Protection Add-Ons', protectionAddOns, 'Protect your valuables during the move.')}
                {renderItemGroup('TV Protection', tvProtectionAddOns)}
            </div>
        </div>

        <div className="lg:col-span-1">
            <LiveQuoteSummary quoteItems={quoteItems} rentalDurationWeeks={rentalDurationWeeks} onItemChange={handleItemChange} />
        </div>
    </div>
  );
}
